import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { getReports, updateReport, getImageUrl } from '../services/api';

function ReportDetail() {
  const { id } = useParams();
  const [report, setReport] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedPhoto, setSelectedPhoto] = useState(null);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchReport();
  }, [id]);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };
    
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const fetchReport = async () => {
    try {
      const response = await getReports();
      const foundReport = response.data.find(r => r.id === parseInt(id));

      if (foundReport) {
        // Check if user has permission to view this report
        if (user.role !== 'admin' && foundReport.user_id !== user.id) {
          setError('You do not have permission to view this report');
          setReport(null);
        } else {
          setReport(foundReport);
        }
      } else {
        setError('Report not found');
      }
    } catch (err) {
      console.error('Error fetching report:', err);
      setError('Failed to load report');
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = async (newStatus) => {
    try {
      await updateReport(id, { status: newStatus });
      setReport({ ...report, status: newStatus });
    } catch (err) {
      alert('Failed to update status');
    }
  };

  const getStatusBadge = (status) => {
    const colors = {
      Pending: { bg: 'linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%)', text: '#1a1a2c' },
      'In Progress': { bg: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)', text: '#fff' },
      Resolved: { bg: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', text: '#fff' }
    };
    const style = colors[status] || { bg: 'linear-gradient(135deg, #6b7280 0%, #4b5563 100%)', text: '#fff' };
    return (
      <span style={{
        background: style.bg,
        color: style.text,
        padding: '6px 14px',
        borderRadius: '30px',
        fontSize: '12px',
        fontWeight: '600',
        display: 'inline-block',
        boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
        letterSpacing: '0.3px'
      }}>
        {status}
      </span>
    );
  };

  const getPriorityBadge = (priority) => {
    const colors = {
      High: { bg: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)', text: '#fff' },
      Medium: { bg: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)', text: '#fff' },
      Low: { bg: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', text: '#fff' }
    };
    const style = colors[priority] || { bg: 'linear-gradient(135deg, #6b7280 0%, #4b5563 100%)', text: '#fff' };
    return (
      <span style={{
        background: style.bg,
        color: style.text,
        padding: '4px 12px',
        borderRadius: '30px',
        fontSize: '11px',
        fontWeight: '600',
        display: 'inline-block',
        boxShadow: '0 2px 6px rgba(0,0,0,0.1)'
      }}>
        {priority}
      </span>
    );
  };

  if (loading) return (
    <div style={{ 
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
      minHeight: '100vh', 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center',
      padding: '20px'
    }}>
      <div style={{ 
        background: 'rgba(255,255,255,0.95)',
        padding: '40px',
        borderRadius: '20px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        textAlign: 'center',
        backdropFilter: 'blur(10px)'
      }}>
        <div className="spinner" style={{
          width: '50px',
          height: '50px',
          border: '3px solid #f3f3f3',
          borderTop: '3px solid #667eea',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite',
          margin: '0 auto 20px'
        }}></div>
        <div style={{ color: '#1a1a2c', fontSize: '18px', fontWeight: '600' }}>
          Loading report details...
        </div>
      </div>
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );

  if (error) return (
    <div style={{ 
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
      minHeight: '100vh', 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center',
      padding: '20px'
    }}>
      <div style={{ 
        background: 'rgba(255,255,255,0.95)',
        padding: '40px',
        borderRadius: '20px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        textAlign: 'center',
        maxWidth: '400px',
        backdropFilter: 'blur(10px)'
      }}>
        <i className="bi bi-exclamation-triangle-fill" style={{ fontSize: '48px', color: '#ef4444', marginBottom: '20px' }}></i>
        <h3 style={{ color: '#1a1a2c', marginBottom: '10px' }}>Access Denied</h3>
        <p style={{ color: '#6b7280', marginBottom: '20px' }}>{error}</p>
        <button
          onClick={() => navigate(-1)}
          style={{
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            color: 'white',
            padding: '12px 24px',
            border: 'none',
            borderRadius: '30px',
            fontSize: '14px',
            fontWeight: '600',
            cursor: 'pointer',
            transition: 'all 0.3s',
            boxShadow: '0 10px 20px rgba(102,126,234,0.3)'
          }}
          onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
          onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
        >
          Go Back
        </button>
      </div>
    </div>
  );

  if (!report) return (
    <div style={{ 
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
      minHeight: '100vh', 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center',
      padding: '20px'
    }}>
      <div style={{ 
        background: 'rgba(255,255,255,0.95)',
        padding: '40px',
        borderRadius: '20px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        textAlign: 'center'
      }}>
        <i className="bi bi-inbox" style={{ fontSize: '48px', color: '#9ca3af', marginBottom: '20px' }}></i>
        <p style={{ color: '#6b7280' }}>Report not found</p>
      </div>
    </div>
  );

  // Double-check permission
  if (user.role !== 'admin' && report.user_id !== user.id) {
    return (
      <div style={{ 
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
        minHeight: '100vh', 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center',
        padding: '20px'
      }}>
        <div style={{ 
          background: 'rgba(255,255,255,0.95)',
          padding: '40px',
          borderRadius: '20px',
          boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
          textAlign: 'center',
          maxWidth: '400px',
          backdropFilter: 'blur(10px)'
        }}>
          <i className="bi bi-shield-lock-fill" style={{ fontSize: '48px', color: '#ef4444', marginBottom: '20px' }}></i>
          <h3 style={{ color: '#1a1a2c', marginBottom: '10px' }}>Unauthorized Access</h3>
          <p style={{ color: '#6b7280', marginBottom: '20px' }}>You do not have permission to view this report</p>
          <button
            onClick={() => navigate('/dashboard')}
            style={{
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              color: 'white',
              padding: '12px 24px',
              border: 'none',
              borderRadius: '30px',
              fontSize: '14px',
              fontWeight: '600',
              cursor: 'pointer',
              transition: 'all 0.3s',
              boxShadow: '0 10px 20px rgba(102,126,234,0.3)'
            }}
            onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
            onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
          >
            Go to Dashboard
          </button>
        </div>
      </div>
    );
  }

  const isAdmin = user && user.role === 'admin';

  return (
    <div style={{
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      minHeight: '100vh',
      padding: isMobile ? '20px 10px 80px 10px' : '30px 20px',
      fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, sans-serif"
    }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        {/* Header with Glass Effect */}
        <div style={{
          background: 'rgba(255,255,255,0.95)',
          backdropFilter: 'blur(10px)',
          borderRadius: '20px',
          padding: '25px',
          marginBottom: '30px',
          boxShadow: '0 20px 40px rgba(0,0,0,0.2)',
          border: '1px solid rgba(255,255,255,0.3)',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          flexWrap: isMobile ? 'wrap' : 'nowrap',
          gap: '20px'
        }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '10px' }}>
              <h1 style={{ 
                color: '#1a1a2c', 
                fontSize: isMobile ? '24px' : '28px', 
                margin: 0,
                fontWeight: '700',
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent'
              }}>
                Report #{report.id}
              </h1>
              {getStatusBadge(report.status)}
            </div>
            <p style={{ color: '#6b7280', fontSize: '14px', margin: 0 }}>
              Submitted on {new Date(report.created_at).toLocaleDateString('en-US', { 
                year: 'numeric', 
                month: 'long', 
                day: 'numeric',
                hour: '2-digit',
                minute: '2-digit'
              })}
            </p>
          </div>
          
          <Link 
            to={isAdmin ? '/admin/reports' : '/dashboard'} 
            style={{
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              color: 'white',
              padding: '12px 24px',
              borderRadius: '30px',
              textDecoration: 'none',
              fontSize: '14px',
              fontWeight: '600',
              transition: 'all 0.3s',
              display: 'inline-flex',
              alignItems: 'center',
              gap: '8px',
              boxShadow: '0 10px 20px rgba(102,126,234,0.3)',
              border: 'none'
            }}
            onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
            onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
          >
            <i className="bi bi-arrow-left"></i>
            Back to {isAdmin ? 'Reports' : 'Dashboard'}
          </Link>
        </div>

        {/* Main Content Card */}
        <div style={{
          background: 'rgba(255,255,255,0.95)',
          backdropFilter: 'blur(10px)',
          borderRadius: '20px',
          boxShadow: '0 20px 40px rgba(0,0,0,0.2)',
          border: '1px solid rgba(255,255,255,0.3)',
          overflow: 'hidden'
        }}>
          {/* Card Header */}
          <div style={{ 
            padding: '20px 25px', 
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            borderBottom: '1px solid rgba(255,255,255,0.1)'
          }}>
            <h2 style={{ color: 'white', margin: 0, fontSize: '20px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '10px' }}>
              <i className="bi bi-info-circle-fill"></i>
              Report Details
            </h2>
          </div>

          <div style={{ padding: '30px' }}>
            {/* Title Section */}
            <div style={{
              background: 'linear-gradient(135deg, #f3f4f6 0%, #e5e7eb 100%)',
              borderRadius: '16px',
              padding: '20px',
              marginBottom: '30px'
            }}>
              <h3 style={{ color: '#1a1a2c', margin: '0 0 10px 0', fontSize: '18px', fontWeight: '600' }}>
                {report.title}
              </h3>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                {getPriorityBadge(report.priority)}
                <span style={{
                  background: '#f3f4f6',
                  color: '#4b5563',
                  padding: '4px 12px',
                  borderRadius: '30px',
                  fontSize: '12px',
                  fontWeight: '500',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '5px'
                }}>
                  <i className="bi bi-tag" style={{ color: '#667eea' }}></i>
                  {report.report_type}
                </span>
                <span style={{
                  background: '#f3f4f6',
                  color: '#4b5563',
                  padding: '4px 12px',
                  borderRadius: '30px',
                  fontSize: '12px',
                  fontWeight: '500',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '5px'
                }}>
                  <i className="bi bi-door-open" style={{ color: '#667eea' }}></i>
                  Room {report.room}
                </span>
              </div>
            </div>

            {/* Two Column Layout */}
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', 
              gap: '25px',
              marginBottom: '30px'
            }}>
              {/* Left Column - Reporter Info */}
              <div style={{
                background: '#f9fafb',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid #e5e7eb'
              }}>
                <h4 style={{ 
                  color: '#1a1a2c', 
                  margin: '0 0 20px 0', 
                  fontSize: '16px', 
                  fontWeight: '600',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-person-badge" style={{ color: '#667eea' }}></i>
                  Reporter Information
                </h4>
                
                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div style={{
                      width: '40px',
                      height: '40px',
                      borderRadius: '12px',
                      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: 'white',
                      fontSize: '16px',
                      fontWeight: '600'
                    }}>
                      {report.author_name?.charAt(0).toUpperCase() || 'U'}
                    </div>
                    <div>
                      <div style={{ color: '#6b7280', fontSize: '12px' }}>Name</div>
                      <div style={{ color: '#1a1a2c', fontWeight: '600' }}>{report.author_name}</div>
                    </div>
                  </div>

                  <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div style={{
                      width: '40px',
                      height: '40px',
                      borderRadius: '12px',
                      background: '#f3f4f6',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: '#667eea'
                    }}>
                      <i className="bi bi-calendar3"></i>
                    </div>
                    <div>
                      <div style={{ color: '#6b7280', fontSize: '12px' }}>Submitted</div>
                      <div style={{ color: '#1a1a2c', fontWeight: '500' }}>
                        {new Date(report.submitted_date).toLocaleString()}
                      </div>
                    </div>
                  </div>

                  {report.in_progress_date && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                      <div style={{
                        width: '40px',
                        height: '40px',
                        borderRadius: '12px',
                        background: '#f3f4f6',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#3b82f6'
                      }}>
                        <i className="bi bi-arrow-repeat"></i>
                      </div>
                      <div>
                        <div style={{ color: '#6b7280', fontSize: '12px' }}>In Progress</div>
                        <div style={{ color: '#1a1a2c', fontWeight: '500' }}>
                          {new Date(report.in_progress_date).toLocaleString()}
                        </div>
                      </div>
                    </div>
                  )}

                  {report.resolved_date && (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                      <div style={{
                        width: '40px',
                        height: '40px',
                        borderRadius: '12px',
                        background: '#f3f4f6',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#10b981'
                      }}>
                        <i className="bi bi-check-circle"></i>
                      </div>
                      <div>
                        <div style={{ color: '#6b7280', fontSize: '12px' }}>Resolved</div>
                        <div style={{ color: '#1a1a2c', fontWeight: '500' }}>
                          {new Date(report.resolved_date).toLocaleString()}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Right Column - Report Info */}
              <div style={{
                background: '#f9fafb',
                borderRadius: '16px',
                padding: '20px',
                border: '1px solid #e5e7eb'
              }}>
                <h4 style={{ 
                  color: '#1a1a2c', 
                  margin: '0 0 20px 0', 
                  fontSize: '16px', 
                  fontWeight: '600',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-clipboard-data" style={{ color: '#667eea' }}></i>
                  Report Details
                </h4>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                  <div>
                    <div style={{ color: '#6b7280', fontSize: '12px', marginBottom: '4px' }}>Description</div>
                    <div style={{ 
                      color: '#1a1a2c', 
                      background: 'white',
                      padding: '15px',
                      borderRadius: '12px',
                      border: '1px solid #e5e7eb',
                      lineHeight: '1.6'
                    }}>
                      {report.description}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Photo Section */}
            {report.photo_path && (
              <div style={{
                marginTop: '20px'
              }}>
                <h4 style={{ 
                  color: '#1a1a2c', 
                  margin: '0 0 15px 0', 
                  fontSize: '16px', 
                  fontWeight: '600',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}>
                  <i className="bi bi-image" style={{ color: '#667eea' }}></i>
                  Attached Photo
                </h4>
                
                <div style={{
                  background: '#f9fafb',
                  borderRadius: '16px',
                  padding: '20px',
                  border: '1px solid #e5e7eb',
                  textAlign: 'center'
                }}>
                  <div style={{
                    display: 'inline-block',
                    position: 'relative',
                    cursor: 'pointer'
                  }}
                  onClick={() => setSelectedPhoto(report.photo_path)}
                  >
                    <div style={{
                      padding: '4px',
                      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                      borderRadius: '16px',
                      boxShadow: '0 20px 40px rgba(102,126,234,0.3)'
                    }}>
                      <img
                        src={getImageUrl(report.photo_path)}
                        alt="Report"
                        style={{
                          maxWidth: '100%',
                          maxHeight: '400px',
                          borderRadius: '12px',
                          display: 'block'
                        }}
                        onError={(e) => {
                          e.target.onerror = null;
                          e.target.src = 'https://via.placeholder.com/400x300?text=Image+Not+Found';
                        }}
                      />
                    </div>
                    <div style={{
                      position: 'absolute',
                      bottom: '10px',
                      right: '10px',
                      background: 'rgba(0,0,0,0.7)',
                      color: 'white',
                      padding: '8px 16px',
                      borderRadius: '30px',
                      fontSize: '13px',
                      backdropFilter: 'blur(5px)',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '5px'
                    }}>
                      <i className="bi bi-zoom-in"></i>
                      Click to enlarge
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Admin Actions */}
        {isAdmin && (
          <div style={{
            background: 'rgba(255,255,255,0.95)',
            backdropFilter: 'blur(10px)',
            borderRadius: '20px',
            boxShadow: '0 20px 40px rgba(0,0,0,0.2)',
            border: '1px solid rgba(255,255,255,0.3)',
            marginTop: '30px',
            overflow: 'hidden'
          }}>
            <div style={{ 
              padding: '20px 25px', 
              background: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)',
              borderBottom: '1px solid rgba(255,255,255,0.1)'
            }}>
              <h3 style={{ color: 'white', margin: 0, fontSize: '18px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '10px' }}>
                <i className="bi bi-shield-lock-fill"></i>
                Admin Actions
              </h3>
            </div>
            
            <div style={{ padding: '25px' }}>
              <label style={{ 
                color: '#1a1a2c', 
                display: 'block', 
                marginBottom: '15px',
                fontSize: '14px',
                fontWeight: '600',
                textTransform: 'uppercase',
                letterSpacing: '0.5px'
              }}>
                <i className="bi bi-arrow-repeat" style={{ color: '#667eea', marginRight: '8px' }}></i>
                Update Report Status
              </label>
              <div style={{ 
                display: 'flex', 
                gap: '15px', 
                flexWrap: 'wrap'
              }}>
                <button
                  onClick={() => handleStatusChange('Pending')}
                  disabled={report.status === 'Pending'}
                  style={{
                    background: report.status === 'Pending' ? '#e5e7eb' : 'linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%)',
                    color: report.status === 'Pending' ? '#9ca3af' : '#1a1a2c',
                    padding: '12px 24px',
                    border: 'none',
                    borderRadius: '30px',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: report.status === 'Pending' ? 'not-allowed' : 'pointer',
                    transition: 'all 0.3s',
                    boxShadow: report.status === 'Pending' ? 'none' : '0 10px 20px rgba(245,158,11,0.3)',
                    flex: isMobile ? '1' : '0 1 auto',
                    minWidth: '120px'
                  }}
                  onMouseEnter={(e) => {
                    if (report.status !== 'Pending') {
                      e.target.style.transform = 'translateY(-2px)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (report.status !== 'Pending') {
                      e.target.style.transform = 'translateY(0)';
                    }
                  }}
                >
                  <i className="bi bi-hourglass"></i> Pending
                </button>
                
                <button
                  onClick={() => handleStatusChange('In Progress')}
                  disabled={report.status === 'In Progress'}
                  style={{
                    background: report.status === 'In Progress' ? '#e5e7eb' : 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)',
                    color: report.status === 'In Progress' ? '#9ca3af' : 'white',
                    padding: '12px 24px',
                    border: 'none',
                    borderRadius: '30px',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: report.status === 'In Progress' ? 'not-allowed' : 'pointer',
                    transition: 'all 0.3s',
                    boxShadow: report.status === 'In Progress' ? 'none' : '0 10px 20px rgba(59,130,246,0.3)',
                    flex: isMobile ? '1' : '0 1 auto',
                    minWidth: '120px'
                  }}
                  onMouseEnter={(e) => {
                    if (report.status !== 'In Progress') {
                      e.target.style.transform = 'translateY(-2px)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (report.status !== 'In Progress') {
                      e.target.style.transform = 'translateY(0)';
                    }
                  }}
                >
                  <i className="bi bi-arrow-repeat"></i> In Progress
                </button>
                
                <button
                  onClick={() => handleStatusChange('Resolved')}
                  disabled={report.status === 'Resolved'}
                  style={{
                    background: report.status === 'Resolved' ? '#e5e7eb' : 'linear-gradient(135deg, #10b981 0%, #059669 100%)',
                    color: report.status === 'Resolved' ? '#9ca3af' : 'white',
                    padding: '12px 24px',
                    border: 'none',
                    borderRadius: '30px',
                    fontSize: '14px',
                    fontWeight: '600',
                    cursor: report.status === 'Resolved' ? 'not-allowed' : 'pointer',
                    transition: 'all 0.3s',
                    boxShadow: report.status === 'Resolved' ? 'none' : '0 10px 20px rgba(16,185,129,0.3)',
                    flex: isMobile ? '1' : '0 1 auto',
                    minWidth: '120px'
                  }}
                  onMouseEnter={(e) => {
                    if (report.status !== 'Resolved') {
                      e.target.style.transform = 'translateY(-2px)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (report.status !== 'Resolved') {
                      e.target.style.transform = 'translateY(0)';
                    }
                  }}
                >
                  <i className="bi bi-check-circle"></i> Resolved
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Photo Modal */}
        {selectedPhoto && (
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.9)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1100,
            padding: '20px',
            animation: 'fadeIn 0.3s ease'
          }} onClick={() => setSelectedPhoto(null)}>
            {/* Background Pattern */}
            <div style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              opacity: 0.1,
              backgroundImage: 'radial-gradient(circle at 20px 20px, #667eea 2px, transparent 0)',
              backgroundSize: '40px 40px',
              pointerEvents: 'none'
            }}></div>
            
            <div style={{ 
              position: 'relative', 
              maxWidth: '90%', 
              maxHeight: '90%',
              animation: 'scaleIn 0.3s ease'
            }} onClick={e => e.stopPropagation()}>
              {/* Image Container with Gradient Border */}
              <div style={{
                padding: '4px',
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                borderRadius: '20px',
                boxShadow: '0 30px 60px rgba(102,126,234,0.4)'
              }}>
                <img 
                  src={getImageUrl(selectedPhoto)} 
                  alt="report full size"
                  style={{ 
                    maxWidth: '100%', 
                    maxHeight: '80vh', 
                    borderRadius: '16px',
                    display: 'block',
                    background: 'white'
                  }}
                />
              </div>
              
              {/* Close Button */}
              <button
                onClick={() => setSelectedPhoto(null)}
                style={{
                  position: 'absolute',
                  top: '-20px',
                  right: '-20px',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '50%',
                  width: '48px',
                  height: '48px',
                  fontSize: '24px',
                  cursor: 'pointer',
                  boxShadow: '0 10px 20px rgba(102,126,234,0.4)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  transition: 'all 0.3s ease',
                  border: '3px solid white',
                  zIndex: 1110
                }}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'scale(1.1) rotate(90deg)';
                  e.target.style.background = 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'scale(1) rotate(0deg)';
                  e.target.style.background = 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)';
                }}
              >
                ×
              </button>
              
              {/* Image Info Bar */}
              <div style={{
                position: 'absolute',
                bottom: '-50px',
                left: '50%',
                transform: 'translateX(-50%)',
                background: 'rgba(255,255,255,0.95)',
                backdropFilter: 'blur(10px)',
                padding: '10px 20px',
                borderRadius: '30px',
                display: 'flex',
                alignItems: 'center',
                gap: '15px',
                boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
                border: '1px solid rgba(255,255,255,0.3)',
                whiteSpace: 'nowrap'
              }}>
                <i className="bi bi-image" style={{ color: '#667eea' }}></i>
                <span style={{ color: '#1a1a2c', fontWeight: '500' }}>Report Image</span>
                <span style={{ color: '#6b7280' }}>•</span>
                <span style={{ color: '#6b7280', fontSize: '13px' }}>
                  Click outside to close
                </span>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Global Styles */}
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        
        @keyframes scaleIn {
          from { 
            transform: scale(0.9);
            opacity: 0;
          }
          to { 
            transform: scale(1);
            opacity: 1;
          }
        }
      `}</style>
    </div>
  );
}

export default ReportDetail;
